//INPUTS 

#define HOME_BUTTON_1 GPIO_NUM_27
#define HOME_BUTTON_2 GPIO_NUM_33

#define STEP_PIN_1 GPIO_NUM_25
#define DIR_PIN_1 GPIO_NUM_26
#define STEP_PIN_2 GPIO_NUM_19
#define DIR_PIN_2 GPIO_NUM_22
//mutex to ensure we do not try to play keys while moving 
EventGroupHandle_t startSync;
EventGroupHandle_t rehomeSync;
EventGroupHandle_t playSyncGroup;

// Define bits for each finger
#define FINGER_1_READY_BIT (1 << 0)
#define FINGER_2_READY_BIT (1 << 1)
#define ALL_FINGERS_READY  (FINGER_1_READY_BIT | FINGER_2_READY_BIT)

void setup() {
  Serial.begin(115200);

  //create syn obj
  startSync = xEventGroupCreate(); 
  rehomeSync = xEventGroupCreate();
  playSyncGroup = xEventGroupCreate();


    /// -------------------- FINGER 1 -----------------------------------

  StepperConfig stepper_cfg_1 = { STEP_PIN_1, DIR_PIN_1, HOME_BUTTON_1, RMT_CHANNEL_0};//for test
  static StepperController stepper_1(stepper_cfg_1, keys_bbbs_R, KEYS_LEN_R, rehomeSync); // stepper
  static VoiceCoilController vc1(5,2, 0, 0.5f, 0.1f, 0.005f,notes_bbbs_R,NOTE_LEN_R ); // voice coil
  // Wire tasks together 
  static Coordinator finger1(vc1.getTaskHandle(), stepper_1.getTaskHandle(), 0, playSyncGroup, FINGER_1_READY_BIT, ALL_FINGERS_READY); //static' ensures the object lives for the entire program lifetime
  vc1.setCoordinatorHandle(finger1.getTaskHandle());
  stepper_1.setCoordinatorHandle(finger1.getTaskHandle());
  /// -----------------------------------------------------------------


    /// -------------------- FINGER 2 -----------------------------------
  //init hardware drivers 
  StepperConfig stepper_cfg_2 = { STEP_PIN_2, DIR_PIN_2, HOME_BUTTON_2, RMT_CHANNEL_1};
  static StepperController stepper_2(stepper_cfg_2, keys_bbbs_L, KEYS_LEN_L, rehomeSync); // stepper
  static VoiceCoilController vc2(9, 10, 1, 0.5f, 0.1f, 0.005f,notes_bbbs_L,NOTE_LEN_L ); // voice coil
  // // // // Wire tasks together 
  static Coordinator finger2(vc2.getTaskHandle(), stepper_2.getTaskHandle(), 1, playSyncGroup, FINGER_2_READY_BIT, ALL_FINGERS_READY); //static' ensures the object lives for the entire program lifetime
  vc2.setCoordinatorHandle(finger2.getTaskHandle());
  stepper_2.setCoordinatorHandle(finger2.getTaskHandle());
  // /// -----------------------------------------------------------------




}  

